function fix_key_format($key_string, $type='private') {
$key_string=trim($key_string);
if (strpos($key_string, 'BEGIN') !==false) {
return $key_string;
}
$key_string=preg_replace('/\s+/', '', $key_string);
if ($type=='private') {
return "-----BEGIN RSA PRIVATE KEY-----\n" .
chunk_split($key_string, 64, "\n") .
"-----END RSA PRIVATE KEY-----";
} else {
return "-----BEGIN PUBLIC KEY-----\n" .
chunk_split($key_string, 64, "\n") .
"-----END PUBLIC KEY-----";
}
}